window.docContents[41].resolve({"/Lecture-2___-Predicate-Logic-and-Sets/#lecture-2":{"contents":"This lecture extends propositional logic with quantifiers and introduces sets, following chapters 2 and 3 of How To Prove It with Lean (HTPIwL). It presents the proof rules for the universal and existential quantifiers, the laws that relate them under negation, and sets as predicates in Lean.\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n","context":"Formal Software Verification","header":"2. Lecture 2: Predicate Logic and Sets","id":"/Lecture-2___-Predicate-Logic-and-Sets/#lecture-2"}});